static from(source: TextureSource, options: IBaseTextureOptions = {},
    strict = settings.STRICT_TEXTURE_CACHE): Texture
{
    const isFrame = typeof source === 'string';
    let cacheId = null;

    if (isFrame)
    {
        cacheId = source;
    }
    else
    {
        if (!(source as any)._pixiId)
        {
            const prefix = (options && options.pixiIdPrefix) || 'pixiid';

            (source as any)._pixiId = `${prefix}_${uid()}`;
        }

        cacheId = (source as any)._pixiId;
    }

    let texture = TextureCache[cacheId];

    // Strict-mode rejects invalid cacheIds
    if (isFrame && strict && !texture)
    {
        throw new Error(`The cacheId "${cacheId}" does not exist in TextureCache.`);
    }

    if (!texture)
    {
        if (!options.resolution)
        {
            options.resolution = getResolutionOfUrl(source as string);
        }

        texture = new Texture(new BaseTexture(source, options));
        texture.baseTexture.cacheId = cacheId;

        BaseTexture.addToCache(texture.baseTexture, cacheId);
        Texture.addToCache(texture, cacheId);
    }

    // lets assume its a base texture!
    return texture;
}

resize(desiredScreenWidth: number, desiredScreenHeight: number): void
{
    this.view.width = Math.round(desiredScreenWidth * this.resolution);
    this.view.height = Math.round(desiredScreenHeight * this.resolution);

    const screenWidth = this.view.width / this.resolution;
    const screenHeight = this.view.height / this.resolution;

    this.screen.width = screenWidth;
    this.screen.height = screenHeight;

    if (this.autoDensity)
    {
        this.view.style.width = `${screenWidth}px`;
        this.view.style.height = `${screenHeight}px`;
    }

    /**
     * Fired after view has been resized.
     * @event PIXI.Renderer#resize
     * @param {number} screenWidth - The new width of the screen.
     * @param {number} screenHeight - The new height of the screen.
     */
    this.emit('resize', screenWidth, screenHeight);
}

