constructor(options: ApolloClientOptions<TCacheShape>) {
  const {
    cache,
    ssrMode = false,
    ssrForceFetchDelay = 0,
    connectToDevTools,
    queryDeduplication = true,
    defaultOptions,
    assumeImmutableResults = false,
    resolvers,
    typeDefs,
    fragmentMatcher,
    name: clientAwarenessName,
    version: clientAwarenessVersion,
  } = options;

  let { link } = options;

  // If a link hasn't been defined, but local state resolvers have been set,
  // setup a default empty link.
  if (!link && resolvers) {
    link = ApolloLink.empty();
  }

  if (!link || !cache) {
    throw new InvariantError(
      "In order to initialize Apollo Client, you must specify 'link' and 'cache' properties in the options object.\n" +
      "These options are part of the upgrade requirements when migrating from Apollo Client 1.x to Apollo Client 2.x.\n" +
      "For more information, please visit: https://www.apollographql.com/docs/tutorial/client.html#apollo-client-setup"
    );
  }

  const supportedCache = new Map<DocumentNode, DocumentNode>();
  const supportedDirectives = new ApolloLink(
    (operation: Operation, forward: NextLink) => {
      let result = supportedCache.get(operation.query);
      if (!result) {
        result = removeConnectionDirectiveFromDocument(operation.query);
        supportedCache.set(operation.query, result);
        supportedCache.set(result, result);
      }
      operation.query = result;
      return forward(operation);
    },
  );

  // remove apollo-client supported directives
  this.link = supportedDirectives.concat(link);
  this.cache = cache;
  this.store = new DataStore(cache);
  this.disableNetworkFetches = ssrMode || ssrForceFetchDelay > 0;
  this.queryDeduplication = queryDeduplication;
  this.defaultOptions = defaultOptions || {};
  this.typeDefs = typeDefs;

  if (ssrForceFetchDelay) {
    setTimeout(
      () => (this.disableNetworkFetches = false),
      ssrForceFetchDelay,
    );
  }

  this.watchQuery = this.watchQuery.bind(this);
  this.query = this.query.bind(this);
  this.mutate = this.mutate.bind(this);
  this.resetStore = this.resetStore.bind(this);
  this.reFetchObservableQueries = this.reFetchObservableQueries.bind(this);

  // Attach the client instance to window to let us be found by chrome devtools, but only in
  // development mode
  const defaultConnectToDevTools =
    process.env.NODE_ENV !== 'production' &&
    typeof window !== 'undefined' &&
    !(window as any).__APOLLO_CLIENT__;

  if (
    typeof connectToDevTools === 'undefined'
      ? defaultConnectToDevTools
      : connectToDevTools && typeof window !== 'undefined'
  ) {
    (window as any).__APOLLO_CLIENT__ = this;
  }

  /**
   * Suggest installing the devtools for developers who don't have them
   */
  if (!hasSuggestedDevtools && process.env.NODE_ENV !== 'production') {
    hasSuggestedDevtools = true;
    if (
      typeof window !== 'undefined' &&
      window.document &&
      window.top === window.self
    ) {
      // First check if devtools is not installed
      if (
        typeof (window as any).__APOLLO_DEVTOOLS_GLOBAL_HOOK__ === 'undefined'
      ) {
        // Only for Chrome
        if (
          window.navigator &&
          window.navigator.userAgent &&
          window.navigator.userAgent.indexOf('Chrome') > -1
        ) {
          // tslint:disable-next-line
          console.debug(
            'Download the Apollo DevTools ' +
              'for a better development experience: ' +
              'https://chrome.google.com/webstore/detail/apollo-client-developer-t/jdkknkkbebbapilgoeccciglkfbmbnfm',
          );
        }
      }
    }
  }

  this.version = version;

  this.localState = new LocalState({
    cache,
    client: this,
    resolvers,
    fragmentMatcher,
  });

  this.queryManager = new QueryManager({
    link: this.link,
    store: this.store,
    queryDeduplication,
    ssrMode,
    clientAwareness: {
      name: clientAwarenessName!,
      version: clientAwarenessVersion!,
    },
    localState: this.localState,
    assumeImmutableResults,
    onBroadcast: () => {
      if (this.devToolsHookCb) {
        this.devToolsHookCb({
          action: {},
          state: {
            queries: this.queryManager.queryStore.getStore(),
            mutations: this.queryManager.mutationStore.getStore(),
          },
          dataWithOptimisticResults: this.cache.extract(true),
        });
      }
    },
  });
}

