constructor(baseTexture: BaseTexture<R>, frame?: Rectangle,
    orig?: Rectangle, trim?: Rectangle, rotate?: number, anchor?: IPointData)
{
    super();

    this.noFrame = false;

    if (!frame)
    {
        this.noFrame = true;
        frame = new Rectangle(0, 0, 1, 1);
    }

    if (baseTexture instanceof Texture)
    {
        baseTexture = baseTexture.baseTexture;
    }

    this.baseTexture = baseTexture;
    this._frame = frame;
    this.trim = trim;
    this.valid = false;
    this._uvs = DEFAULT_UVS;
    this.uvMatrix = null;
    this.orig = orig || frame;// new Rectangle(0, 0, 1, 1);

    this._rotate = Number(rotate || 0);

    if (rotate as any === true)
    {
        // this is old texturepacker legacy, some games/libraries are passing "true" for rotated textures
        this._rotate = 2;
    }
    else if (this._rotate % 2 !== 0)
    {
        throw new Error('attempt to use diamond-shaped UVs. If you are sure, set rotation manually');
    }

    this.defaultAnchor = anchor ? new Point(anchor.x, anchor.y) : new Point(0, 0);

    this._updateID = 0;

    this.textureCacheIds = [];

    if (!baseTexture.valid)
    {
        baseTexture.once('loaded', this.onBaseTextureUpdated, this);
    }
    else if (this.noFrame)
    {
        // if there is no frame we should monitor for any base texture changes..
        if (baseTexture.valid)
        {
            this.onBaseTextureUpdated(baseTexture);
        }
    }
    else
    {
        this.frame = frame;
    }

    if (this.noFrame)
    {
        baseTexture.on('update', this.onBaseTextureUpdated, this);
    }
}

export function drawChamferRect(this: Graphics,
    x: number,
    y: number,
    width: number,
    height: number,
    chamfer: number): Graphics
{
    if (chamfer <= 0)
    {
        return this.drawRect(x, y, width, height);
    }

    const inset = Math.min(chamfer, Math.min(width, height) / 2);
    const right = x + width;
    const bottom = y + height;
    const points = [
        x + inset, y,
        right - inset, y,
        right, y + inset,
        right, bottom - inset,
        right - inset, bottom,
        x + inset, bottom,
        x, bottom - inset,
        x, y + inset,
    ];

    // Remove overlapping points
    for (let i = points.length - 1; i >= 2; i -= 2)
    {
        if (points[i] === points[i - 2] && points[i - 1] === points[i - 3])
        {
            points.splice(i - 1, 2);
        }
    }

    return this.drawPolygon(points);
}

