export function string2hex(string: string): number
{
    if (typeof string === 'string')
    {
        string = (cssColorNames as {[key: string]: string})[string.toLowerCase()] || string;

        if (string[0] === '#')
        {
            string = string.substr(1);
        }
    }

    return parseInt(string, 16);
}

/**
 * Converts a color as an [R, G, B] array of normalized floats to a hexadecimal number.
 *
 * @example
 * PIXI.utils.rgb2hex([1, 1, 1]); // returns 0xffffff
 * @memberof PIXI.utils
 * @function rgb2hex
 * @param {number[]} rgb - Array of numbers where all values are normalized floats from 0.0 to 1.0.
 * @return {number} Number in hexadecimal.
 */
export function rgb2hex(rgb: number[] | Float32Array): number

contextChange(): void
{
    const gl = this.renderer.gl;

    if (settings.PREFER_ENV === ENV.WEBGL_LEGACY)
    {
        this.maxTextures = 1;
    }
    else
    {
        // step 1: first check max textures the GPU can handle.
        this.maxTextures = Math.min(
            gl.getParameter(gl.MAX_TEXTURE_IMAGE_UNITS),
            BatchRenderer.maxTextures);

        // step 2: check the maximum number of if statements the shader can have too..
        this.maxTextures = checkMaxIfStatementsInShader(
            this.maxTextures, gl);
    }

    this._shader = this.shaderGenerator.generateShader(this.maxTextures);

    // we use the second shader as the first one depending on your browser
    // may omit aTextureId as it is not used by the shader so is optimized out.
    for (let i = 0; i < this._packedGeometryPoolSize; i++)
    {
        /* eslint-disable max-len */
        this._packedGeometries[i] = new (this.geometryClass)();
    }

    this.initFlushBuffers();
}

