constructor(vertexSrc?: string, fragmentSrc?: string, name = 'pixi-shader')
{
    this.id = UID++;
    this.vertexSrc = vertexSrc || Program.defaultVertexSrc;
    this.fragmentSrc = fragmentSrc || Program.defaultFragmentSrc;

    this.vertexSrc = this.vertexSrc.trim();
    this.fragmentSrc = this.fragmentSrc.trim();

    if (this.vertexSrc.substring(0, 8) !== '#version')
    {
        name = name.replace(/\s+/g, '-');

        if (nameCache[name])
        {
            nameCache[name]++;
            name += `-${nameCache[name]}`;
        }
        else
        {
            nameCache[name] = 1;
        }

        this.vertexSrc = `#define SHADER_NAME ${name}\n${this.vertexSrc}`;
        this.fragmentSrc = `#define SHADER_NAME ${name}\n${this.fragmentSrc}`;

        this.vertexSrc = setPrecision(this.vertexSrc, settings.PRECISION_VERTEX, PRECISION.HIGH);
        this.fragmentSrc = setPrecision(this.fragmentSrc, settings.PRECISION_FRAGMENT, getMaxFragmentPrecision());
    }

    // currently this does not extract structs only default types
    // this is where we store shader references..
    this.glPrograms = {};

    this.syncUniforms = null;
}

constructor(...points: any[])
{
    let flat: IPointData[]|number[] = Array.isArray(points[0]) ? points[0] : points;

    // if this is an array of points, convert it to a flat array of numbers
    if (typeof flat[0] !== 'number')
    {
        const p: number[] = [];

        for (let i = 0, il = flat.length; i < il; i++)
        {
            p.push((flat[i] as IPointData).x, (flat[i] as IPointData).y);
        }

        flat = p;
    }

    /**
     * An array of the points of this polygon
     *
     * @member {number[]}
     */
    this.points = flat as number[];

    /**
     * The type of the object, mainly used to avoid `instanceof` checks
     *
     * @member {number}
     * @readOnly
     * @default PIXI.SHAPES.POLY
     * @see PIXI.SHAPES
     */
    this.type = SHAPES.POLY;

    /**
     * `false` after moveTo, `true` after `closePath`. In all other cases it is `true`.
     * @member {boolean}
     * @default true
     */
    this.closeStroke = true;
}

constructor(source: Float32Array|Uint8Array|Uint16Array|Uint32Array, options: ISize)
{
    const { width, height } = options || {};

    if (!width || !height)
    {
        throw new Error('BufferResource width or height invalid');
    }

    super(width, height);

    this.data = source;
}

function findText(item: IDisplayObjectExtended, queue: Array<any>): boolean
{
    if (item instanceof Text)
    {
        // push the text style to prepare it - this can be really expensive
        if (queue.indexOf(item.style) === -1)
        {
            queue.push(item.style);
        }
        // also push the text object so that we can render it (to canvas/texture) if needed
        if (queue.indexOf(item) === -1)
        {
            queue.push(item);
        }
        // also push the Text's texture for upload to GPU
        const texture = item._texture.baseTexture;

        if (queue.indexOf(texture) === -1)
        {
            queue.push(texture);
        }

        return true;
    }

    return false;
}

